import { createClient } from '@supabase/supabase-js';

const supabaseUrl = process.env.REACT_APP_SUPABASE_URL;
const supabaseAnonKey = process.env.REACT_APP_SUPABASE_ANON_KEY;

function makeDummyClient() {
  const msg = 'Supabase is not configured. Set REACT_APP_SUPABASE_URL and REACT_APP_SUPABASE_ANON_KEY in .env.local';
  const chainable = () => {
    const result = Promise.resolve({ data: null, error: { message: msg } });
    const proxy = new Proxy({}, {
      get: () => () => proxy,
    });
    proxy.then = result.then.bind(result);
    proxy.catch = result.catch.bind(result);
    return proxy;
  };

  return {
    from: () => chainable(),
    storage: {
      from: () => ({ upload: async () => ({ data: null, error: { message: msg } }) }),
    },
    auth: {
      signUp: async () => ({ data: null, error: { message: msg } }),
      signInWithPassword: async () => ({ data: null, error: { message: msg } }),
      signOut: async () => ({ error: { message: msg } }),
    },
  };
}

let supabase;
const isProd = process.env.NODE_ENV === 'production';
if (!supabaseUrl || !supabaseAnonKey) {
  const msg = 'Supabase URL or ANON KEY is not set in environment variables.';
  if (isProd) {
    throw new Error(`${msg} Add REACT_APP_SUPABASE_URL and REACT_APP_SUPABASE_ANON_KEY during build for production.`);
  }
  console.warn(msg + ' Falling back to dummy client for development.');
  supabase = makeDummyClient();
} else {
  supabase = createClient(supabaseUrl, supabaseAnonKey);
}

export { supabase };
